	bool Validate()
	{
		uchar* pktStart = (uchar*)this;
		uint16 pktSize = mPktSize;

		uint16 dataSize = sizeof(PKT_SC_USER_BASIC_DATA_READ);
		if (dataSize > mPktSize)
			return false;

		if (false == ValidateValue(pktStart, pktSize, dataSize))
			return false;

		if (dataSize != mPktSize)
			return false;

		return true;
	}

	bool ValidateValue(const uchar* pktStart, uint16 pktSize, uint16& dataSize)
	{
		if (false == ValidateString(mUserNameOffset, 0, pktStart, pktSize, dataSize))
			return false;

		if (false == ValidateString(mHomeWorldPrefixOffset, 0, pktStart, pktSize, dataSize))
			return false;

		if (false == ValidateString(mGmPrefixOffset, 0, pktStart, pktSize, dataSize))
			return false;

		if (false == ValidateBinary(mBossBookMarkListOffset, mBossBookMarkListSize, 0, pktSize, dataSize))
			return false;

		return (nullptr != pktStart && 0 < pktSize && 0 < dataSize) ? true : false;
	}

