	{
		auto ResultItemDecomposeListLogFunc = [this]() -> std::xwstring
		{
			std::xwstring result;
			result.append(L"\n");
			for (int offset = 0; offset < ResultItemDecomposeSize(); offset += sizeof(struct ItemIdAmountPair))
			{
				const struct ItemIdAmountPair* data = reinterpret_cast<const struct ItemIdAmountPair*>(ResultItemDecompose() + offset);
				result.append(Log::format(L"{}", *data));
				result.append(L"\n");
			}
			return result;
		};


		return Log::format(
			L"[SC_ACK_ITEM_DECOMPOSE] Result: {}, IsAutoDecompose: {}, ResultItemDecompose: {}"
			, mResult, mIsAutoDecompose, ResultItemDecomposeListLogFunc().c_str()
		).c_str();
	}
