		mRecommendListCount = (uint16*)mPktWriter.GetBuffer();
		*mRecommendListCount = 0;
		mPktWriter << (*mRecommendListCount);
		mFirstRecommendListOffset = (uint16*)mPktWriter.GetBuffer();
		*mFirstRecommendListOffset = 0;
