	uint64 Duration() { return mDuration; }
	uint32 ColorRGB() { return mColorRGB; }
	const uchar* Pos() const
	{
		uchar* pktStart = (uchar*)this;
		uint16 pktSize = *((uint16*)pktStart);
		if (mPosOffset && pktSize > mPosOffset)
			return (const uchar*)(pktStart + mPosOffset);
		else
			return 0;
	}
	int PosSize() const
	{
		return mPosSize;
	}
#ifdef _SERVER
	template <typename Container>
	void MakePosVector(Container & container)
	{
		//emplace() ČŁĂâÇŇ¶§¸¶´Ů ¸Ţ¸đ¸®¸¦ »ýĽş ÇĎ´Â şńżëŔĚ ąß»ýÇŃ´Ů şńżëŔ»ÁŮŔĚŔ§°ł reserve()»çżë
		container.reserve(mPosSize/sizeof(_T0));
		for (int offset = 0; offset < mPosSize; offset += sizeof(_T0))
		{
			const _T0* data = reinterpret_cast<const _T0*>(Pos() + offset);
			container.emplace_back(*data);
		}
	}
#else // _SERVER
	template <typename Container, typename Data>
	void MakePosVector(Container & container)
	{
		for (int offset = 0; offset < mPosSize; offset += sizeof(Data))
		{
			const Data* data = reinterpret_cast<const Data*>(Pos() + offset);
			container.Add(*data);
		}
	}
#endif // _SERVER
#ifdef _SERVER
	template <typename TFunc>
	void ForEachPos(TFunc&& func) const
	{
		for (int offset = 0; offset < PosSize(); offset += sizeof(_T0))
		{
			const _T0* data = reinterpret_cast<const _T0*>(Pos() + offset);
			func(data);
		}
	}
#endif


#ifdef _SERVER 
	std::xwstring GetLogWString() const
	{

		return Log::format(
			L"[SC_DEBUG_SHAPE_LINE] GameId: {}, Duration: {}, ColorRGB: {}"
			, mGameId, mDuration, mColorRGB
		).c_str();
	}
#endif

	bool Validate()
	{
		uchar* pktStart = (uchar*)this;
		uint16 pktSize = mPktSize;

		uint16 dataSize = sizeof(PKT_SC_DEBUG_SHAPE_LINE_READ);
		if (dataSize > mPktSize)
			return false;

		if (false == ValidateValue(pktStart, pktSize, dataSize))
			return false;

		if (dataSize != mPktSize)
			return false;

		return true;
	}

	bool ValidateValue(const uchar* pktStart, uint16 pktSize, uint16& dataSize)
	{
		if (false == ValidateBinary(mPosOffset, mPosSize, 0, pktSize, dataSize))
			return false;

		return (nullptr != pktStart && 0 < pktSize && 0 < dataSize) ? true : false;
	}

