	{
		uchar* pktStart = (uchar*)this;
		uint16 pktSize = *((uint16*)pktStart);
		if (mStatInfoOffset && pktSize > mStatInfoOffset)
			return (const uchar*)(pktStart + mStatInfoOffset);
		else
			return 0;
	}
	int StatInfoSize() const
	{
		return mStatInfoSize;
	}
#ifdef _SERVER
	template <typename Container>
	void MakeStatInfoVector(Container & container)
	{
		//emplace() ČŁĂâÇŇ¶§¸¶´Ů ¸Ţ¸đ¸®¸¦ »ýĽş ÇĎ´Â şńżëŔĚ ąß»ýÇŃ´Ů şńżëŔ»ÁŮŔĚŔ§°ł reserve()»çżë
		container.reserve(mStatInfoSize/sizeof(_T0));
		for (int offset = 0; offset < mStatInfoSize; offset += sizeof(_T0))
		{
			const _T0* data = reinterpret_cast<const _T0*>(StatInfo() + offset);
			container.emplace_back(*data);
		}
	}
#else // _SERVER
	template <typename Container, typename Data>
	void MakeStatInfoVector(Container & container)
	{
		for (int offset = 0; offset < mStatInfoSize; offset += sizeof(Data))
		{
			const Data* data = reinterpret_cast<const Data*>(StatInfo() + offset);
			container.Add(*data);
		}
	}
#endif // _SERVER
#ifdef _SERVER
	template <typename TFunc>
	void ForEachStatInfo(TFunc&& func) const
	{
		for (int offset = 0; offset < StatInfoSize(); offset += sizeof(_T0))
		{
			const _T0* data = reinterpret_cast<const _T0*>(StatInfo() + offset);
			func(data);
		}
	}
#endif


