		ContentsList* newContentsList = new ((ContentsList*)nowBuffer) ContentsList(nowWritten, contentsType, contentsState);
		++(*mContentsListCount);
		if (mNowContentsList == 0)
			*mFirstContentsListOffset = nowWritten;
		else
			mNowContentsList->mNextOffset = nowWritten;
		mNowContentsList = newContentsList;
		mPktWriter.Skip(sizeof(ContentsList));
