		mPktWriter << (*mExpiredItemIdListSize);
		*mExpiredItemIdListOffset = (uint16)mPktWriter.GetPktSize();
		if (expiredItemIdList && !expiredItemIdList->empty())
		{
			int tvalsize = (int)sizeof(*(expiredItemIdList->begin())); 
			auto _expiredItemIdList = const_cast<std::decay_t<T0>*>(expiredItemIdList);
			for (auto it = _expiredItemIdList->begin(); it != _expiredItemIdList->end(); ++it) 
			{
				mPktWriter.WriteBinary((uint16)tvalsize, (uchar*)&(*it)); 
			}
			*mExpiredItemIdListSize = (uint16) (tvalsize * expiredItemIdList->size());
		}
