			if (mNowSlotList == 0)
				mActivatedSlateList->mFirstSlotListOffset = nowWritten;
			else
				mNowSlotList->mNextOffset = nowWritten;
			mNowSlotList = newSlotList;
			mPktWriter.Skip(sizeof(ActivatedSlateList::SlotList));
			return SlotListHandle(mPktWriter, newSlotList);
