		mCurrencyFinalOffset = (uint16*)mPktWriter.GetBuffer();
		*mCurrencyFinalOffset = 0;
		mPktWriter << (*mCurrencyFinalOffset);
		mCurrencyFinalSize = (uint16*)mPktWriter.GetBuffer();
