		if (dataSize > mPktSize)
			return false;

		if (false == ValidateValue(pktStart, pktSize, dataSize))
			return false;

		if (false == BehaviorStatusArrayValidateListNode(mFirstBehaviorStatusArrayOffset, pktStart, pktSize, dataSize))
			return false;

