	{
		static_assert(true == std::is_same_v<T0::value_type, _T0>, "SpaceCrackActivationList type must be SpaceCrackActivation list type"); 
		mPktWriter << (uint16)SC_SPACE_CRACK_ACTIVATION_LIST;
		mSpaceCrackActivationListOffset = (uint16*)mPktWriter.GetBuffer();
		*mSpaceCrackActivationListOffset = 0;
		mPktWriter << (*mSpaceCrackActivationListOffset);
		mSpaceCrackActivationListSize = (uint16*)mPktWriter.GetBuffer();
		*mSpaceCrackActivationListSize = 0;
		mPktWriter << (*mSpaceCrackActivationListSize);
		*mSpaceCrackActivationListOffset = (uint16)mPktWriter.GetPktSize();
		if (SpaceCrackActivationList && !SpaceCrackActivationList->empty())
		{
			int tvalsize = (int)sizeof(*(SpaceCrackActivationList->begin())); 
			auto _SpaceCrackActivationList = const_cast<std::decay_t<T0>*>(SpaceCrackActivationList);
			for (auto it = _SpaceCrackActivationList->begin(); it != _SpaceCrackActivationList->end(); ++it) 
			{
				mPktWriter.WriteBinary((uint16)tvalsize, (uchar*)&(*it)); 
			}
			*mSpaceCrackActivationListSize = (uint16) (tvalsize * SpaceCrackActivationList->size());
		}
	}
