		friend PktIterator<Rankinglist>;
		friend PKT_SC_WORLD_BOSS_CLEAR_READ;

		bool Validate(uint16 offset, uchar * pktStart, uint16 pktSize, uint16& dataSize)
		{
			if (static_cast<size_t>(pktSize) < static_cast<size_t>(offset) + sizeof(Rankinglist))
				return false;

			Rankinglist * node = (Rankinglist*)(pktStart + offset);

			// ŔÚ±â ŔÚ˝ĹŔÇ Ć÷ŔÎĹÍ °ËÁő
			if (offset != node->mThisOffset)
				return false;

			// Value °ËÁő
			uchar* pktCurrentNodeStart = (uchar*)this - mThisOffset;
			uint16 pktCurrentNodeSize = *((uint16*)pktStart);
			dataSize += sizeof(Rankinglist);	// skip
			if (false == ValidateValue(pktCurrentNodeStart, pktCurrentNodeSize, dataSize))
				return false;

			if (false == Rankinglist::RewardItemListValidateListNode(mFirstRewardItemListOffset, pktStart, pktSize, dataSize))
				return false;

			if (false == Rankinglist::BasicRewardItemListValidateListNode(mFirstBasicRewardItemListOffset, pktStart, pktSize, dataSize))
				return false;

			return true;
		}

		bool RewardItemListValidateListNode(uint16 offset, uchar * pktStart, uint16 pktSize, uint16& dataSize)
		{
			for (RewardItemListIterator iter = this->GetFirstRewardItemListIterator();
				iter != GetLastRewardItemListIterator(); ++iter)
			{
				if (false == (*iter).Validate(offset, pktStart, pktSize, dataSize))
				{
					return false;
				}
			}
			return true;
		}

		bool BasicRewardItemListValidateListNode(uint16 offset, uchar * pktStart, uint16 pktSize, uint16& dataSize)
		{
			for (BasicRewardItemListIterator iter = this->GetFirstBasicRewardItemListIterator();
				iter != GetLastBasicRewardItemListIterator(); ++iter)
			{
				if (false == (*iter).Validate(offset, pktStart, pktSize, dataSize))
				{
					return false;
				}
			}
			return true;
		}

		bool ValidateValue(const uchar* pktStart, uint16 pktSize, uint16& dataSize)
		{
			if (false == ValidateString(mCharNameOffset, 0, pktStart, pktSize, dataSize))
				return false;

			if (false == ValidateString(mGuildNameOffset, 0, pktStart, pktSize, dataSize))
				return false;

			return (nullptr != pktStart && 0 < pktSize && 0 < dataSize) ? true : false;
		}

