	std::xwstring FuncCreateRankinglistStr( [[maybe_unused]] RankinglistIterator& iter) const
	{
		return Log::format(
			L"Rank: {}, CharName: {}, GuildDBId: {}, GuildName: {}, GuildEmblemId: {}, ContributePoint: {}, PvpAlignmentGrade: {}, IsAlive: {}, BasicRewardGold: {}", 
			iter->Rank(), iter->CharName(), iter->GuildDBId(), iter->GuildName(), iter->GuildEmblemId(), iter->ContributePoint(), iter->PvpAlignmentGrade(), iter->IsAlive(), iter->BasicRewardGold()
		).c_str();
	}

	std::xwstring FuncCreateLastHitRewardlistStr( [[maybe_unused]] LastHitRewardlistIterator& iter) const
	{
		return Log::format(
			L"Item: {}", 
			iter->Item()
		).c_str();
	}

	std::xwstring GetLogWString() const
	{
		std::xwstring str1;
		str1.append(L"\n");
		for (RankinglistIterator iter = this->GetFirstRankinglistIterator();
			iter != GetLastRankinglistIterator(); ++iter)
		{
			str1.append(L"[");
			str1.append(FuncCreateRankinglistStr(iter).c_str());

			for (Rankinglist::RewardItemListIterator RewardItemListIter = iter->GetFirstRewardItemListIterator();
				RewardItemListIter != iter->GetLastRewardItemListIterator(); ++RewardItemListIter)
			{
				str1.append(FuncCreateRewardItemListStr(RewardItemListIter).c_str());

			}

			for (Rankinglist::BasicRewardItemListIterator BasicRewardItemListIter = iter->GetFirstBasicRewardItemListIterator();
				BasicRewardItemListIter != iter->GetLastBasicRewardItemListIterator(); ++BasicRewardItemListIter)
			{
				str1.append(FuncCreateBasicRewardItemListStr(BasicRewardItemListIter).c_str());

			}

			str1.append(L"]\n");
		}
		std::xwstring str2;
		str2.append(L"\n");
		for (LastHitRewardlistIterator iter = this->GetFirstLastHitRewardlistIterator();
			iter != GetLastLastHitRewardlistIterator(); ++iter)
		{
			str2.append(L"[");
			str2.append(FuncCreateLastHitRewardlistStr(iter).c_str());

			str2.append(L"]\n");
		}

		return Log::format(
			L"[SC_WORLD_BOSS_CLEAR] BossId: {}, LastHituserName: {}, Rankinglist : {}, LastHitRewardlist : {}"
			, mBossId, LastHituserName(), str1.c_str(), str2.c_str()
		).c_str();
	}
