	{		for (LastHitRewardlistIterator iter = this->GetFirstLastHitRewardlistIterator();
			iter != GetLastLastHitRewardlistIterator(); ++iter)
		{
			if (false == (*iter).Validate(offset, pktStart, pktSize, dataSize))
			{
				return false;
			}
		}
		return true;
	}

	bool ValidateValue(const uchar* pktStart, uint16 pktSize, uint16& dataSize)
	{
		if (false == ValidateString(mLastHituserNameOffset, 0, pktStart, pktSize, dataSize))
			return false;

		return (nullptr != pktStart && 0 < pktSize && 0 < dataSize) ? true : false;
	}

